const html = $('Fetch Gumtree Listings').first().json().data || '';

const now = new Date().toISOString();
const listings = [];

// Extract listing blocks via regex (Gumtree HTML structure)
const itemRegex = /data-ad-id="(\w+)"[^>]*>([\s\S]*?)(?=data-ad-id=|\$)/g;
const titleRegex = /article-title[^<]*>([^<]+)</i;
const priceRegex = /price[^<]*>[^<]*\$([\<]+)</i;
const dateRegex = /date[time]?="([^'"]+)"/i;
const linkRegex = /href="(https:\/\/www\.gumtree\.com\.au\/s\-ad\/[^"]+)"/i;

const blocksRegex = /<li[^>]*class=["'][^"']*listing["'][\s\S]*?><\/li>/g;
let block;

while ((block = blocksRegex.exec(html)) !== null) {
  const htmlBlock = block[0];

  const titleMatch = htmlBlock.match(titleRegex);
  const priceMatch = htmlBlock.match(priceRegex);
  const dateMatch = htmlBlock.match(dateRegex);
  const linkMatch = htmlBlock.match(linkRegex);

  if (titleMatch) {
    listings.push({
      title: titleMatch[1].trim(),
      price: priceMatch ? `$${priceMatch[1].trim()}` : null,
      listed_at: dateMatch ? dateMatch[1] : null,
      url: linkMatch ? linkMatch[1] : null,
    });
  }
}

// Fallback: if no listings parsed, record a status snapshot
if (listings.length === 0) {
  listings.push({
    title: '[Scrape Attempt - No Listings Parsed]',
    price: null,
    listed_at: null,
    url: null,
  });
}

return listings.map(item => ({
  json: {
    factor_type: 'gumtree_airport_transfer',
    market: 'melbourne',
    source: 'gumtree',
    title: item.title,
    price: item.price,
    listed_at: item.listed_at,
    url: item.url,
    snapshot_time: now,
    raw_count: listings.length,
  }
}));
